"use client";

import { TeamProgressBarLabel } from "./parts/team-progress-bar-label";
import { TeamProgressBarRoot } from "./parts/team-progress-bar-root";
import { TeamProgressBarTrack } from "./parts/team-progress-bar-track";
import type { TeamProgressBar01Props } from "./types";

/**
 * Tier A — the batteries-included assembly: `Root` + `Label` (gated by
 * `showLabel`) + `Track` (threading `showTicks`). Contains **no logic the parts
 * don't** — a hand-assembled layout (`TeamProgressBarRoot` + a subset of parts)
 * gets identical resolution + identical single-fire telemetry.
 *
 * One team, one milestone-completion %, always visible, read-only. No comparison,
 * no ranking, no second series — ever (system §5.3 / D-08).
 */
export function TeamProgressBar01({
  milestones,
  value,
  team,
  showLabel = true,
  showTicks = false,
  labelFormat = "percent",
  onEvent,
  className,
  "aria-label": ariaLabel,
}: TeamProgressBar01Props) {
  return (
    <TeamProgressBarRoot
      milestones={milestones}
      value={value}
      team={team}
      labelFormat={labelFormat}
      onEvent={onEvent}
      className={className}
    >
      {showLabel ? <TeamProgressBarLabel /> : null}
      <TeamProgressBarTrack showTicks={showTicks} aria-label={ariaLabel} />
    </TeamProgressBarRoot>
  );
}

// Tier A — batteries-included assembly.
export { TeamProgressBar01 } from "./team-progress-bar-01";

// Tier B — headless provider + flat à-la-carte parts.
export { TeamProgressBarRoot } from "./parts/team-progress-bar-root";
export { TeamProgressBarTrack } from "./parts/team-progress-bar-track";
export { TeamProgressBarLabel } from "./parts/team-progress-bar-label";

// Tier C — context-free primitive.
export { ProgressTrack } from "./parts/team-progress-bar-track";

// Context consumer for hand-assembled layouts.
export { useTeamProgressBar } from "./hooks/use-team-progress-bar";

// Public types.
export type {
  TeamProgressBar01Props,
  TeamProgressBarRootProps,
  TeamProgressBarBaseProps,
  TeamProgressBarContextValue,
  ProgressTrackProps,
  Milestone,
  TeamProgressBarTeam,
  GamificationEvent,
  ProgressLabelFormat,
  ProgressTick,
  ResolvedProgress,
} from "./types";

import type { ReactNode } from "react";

/**
 * `team-progress-bar-01` — public type surface.
 *
 * Framework-free (no `"use client"`): importable from a server component's
 * type position. Per system D-03 every type this component needs is
 * **re-declared locally** — it imports nothing from another registry component.
 * The `gamification-system` description (§4 domain model, §6 telemetry union) is
 * the source of truth these slices are copied from, not imported.
 */

/**
 * A planned team milestone — the shared spine progress derives from (system D-09).
 * Re-declared locally per D-03; do not fork the system's canonical shape.
 */
export interface Milestone {
  id: string;
  /** Human label — shown as a tick-mark tooltip. e.g. "First playable build". */
  label: string;
  /** Counts toward the numerator when true. */
  done: boolean;
  /** ISO 8601 — reserved; not rendered by the bar. */
  doneAt?: string;
  /** Left-to-right tick ordering on the track. */
  order: number;
}

/**
 * This team — the identity subset (system D-15). `id` scopes the telemetry
 * payload; `name` is the optional leading label. Never a bare `teamId`+`teamName`
 * pair because this component renders the team name as text.
 */
export interface TeamProgressBarTeam {
  id: string;
  name?: string;
}

/**
 * The single semantic event this component emits — a narrow local slice of the
 * system §6 `GamificationEvent` union. A consumer's `onEvent` is correctly typed
 * to receive only what this bar sends.
 */
export type GamificationEvent = {
  type: "progress-bar.checked";
  teamId: string;
};

/** Numeric readout style. `"fraction"` requires `milestones`. */
export type ProgressLabelFormat = "percent" | "fraction";

/** One tick notch — derived from a milestone. */
export interface ProgressTick {
  done: boolean;
  label: string;
}

/** Pure resolver output (see `lib/resolve-progress.ts`). SSR-deterministic. */
export interface ResolvedProgress {
  /** Clamped 0..100 integer. */
  pct: number;
  /** Numerator in milestone mode; `null` in direct-value mode. */
  doneCount: number | null;
  /** Denominator in milestone mode; `null` in direct-value mode. */
  total: number | null;
  /** Ordered ticks; `null` when no milestones supplied. */
  ticks: ProgressTick[] | null;
}

/** Data + telemetry surface shared by the assembly and the headless `Root`. */
export interface TeamProgressBarBaseProps {
  /** Milestones for this team; % = done/total. Enables ticks + the fraction readout. */
  milestones?: Milestone[];
  /** Direct 0–100 percentage; wins over `milestones` if both supplied. */
  value?: number;
  /** This team (system D-15). `id` → telemetry payload + scope; `name` → label. */
  team: TeamProgressBarTeam;
  /** Readout style. Default `"percent"`. `"fraction"` falls back to percent without milestones. */
  labelFormat?: ProgressLabelFormat;
  /** Telemetry — emits `{ type: "progress-bar.checked"; teamId }` once per mount. */
  onEvent?: (event: GamificationEvent) => void;
  className?: string;
}

/** Props for the headless provider `TeamProgressBarRoot`. */
export interface TeamProgressBarRootProps extends TeamProgressBarBaseProps {
  children: ReactNode;
}

/** Props for the batteries-included `TeamProgressBar01` assembly. */
export interface TeamProgressBar01Props extends TeamProgressBarBaseProps {
  /** Numeric readout. Default `true`. */
  showLabel?: boolean;
  /** Per-milestone tick notches. Default `false` (needs `milestones`). */
  showTicks?: boolean;
  "aria-label"?: string;
}

/** Props for the context-free Tier-C `ProgressTrack` primitive. */
export interface ProgressTrackProps {
  /** Clamped 0..100 fill percentage. */
  pct: number;
  /** Ordered ticks to overlay (when `showTicks`). */
  ticks?: ProgressTick[] | null;
  /** Render the tick notches. Default `false`. */
  showTicks?: boolean;
  className?: string;
  "aria-label"?: string;
}

/** The resolved value every context part reads — one source of truth. */
export interface TeamProgressBarContextValue {
  pct: number;
  doneCount: number | null;
  total: number | null;
  ticks: ProgressTick[] | null;
  team: TeamProgressBarTeam;
  /** The *effective* format (after the fraction→percent fallback). */
  labelFormat: ProgressLabelFormat;
}

import type { Milestone, ProgressLabelFormat, ResolvedProgress } from "../types";

/**
 * The one piece of real logic — pure, SSR-deterministic (derives only from
 * props; never reads `Date`, layout, or env at module scope). Test-ready and a
 * prime candidate to hoist into a shared `gamification-kit` once 2–3 components
 * prove the surface (system §7.3) — keep it standalone, never inline it.
 */

function clamp(n: number, lo: number, hi: number): number {
  return Math.min(Math.max(n, lo), hi);
}

/** Dev-only warning. The `NODE_ENV` guard is the one sanctioned env reference
 *  (erased in production builds); kept inside the function body, never at module scope. */
function devWarn(message: string): void {
  if (process.env.NODE_ENV !== "production") {
    console.warn(message);
  }
}

function ticksFrom(milestones: Milestone[]): ResolvedProgress["ticks"] {
  // Sort a *copy* — never mutate the prop array.
  return [...milestones]
    .sort((a, b) => a.order - b.order)
    .map((m) => ({ done: m.done, label: m.label }));
}

/**
 * Resolution order (deterministic, locked — description §4 / plan §5):
 *   value present   → pct = clamp(round(value), 0, 100); counts null; ticks from milestones if any
 *   milestones      → pct = total===0 ? 0 : round(done/total*100); counts + ticks set
 *   neither         → 0% (always-visible rule — never hidden, never NaN)
 */
export function resolveProgress(args: {
  value?: number;
  milestones?: Milestone[];
}): ResolvedProgress {
  const { value, milestones } = args;

  if (value != null) {
    if (milestones?.length) {
      devWarn(
        "[team-progress-bar-01] both `value` and `milestones` supplied; `value` takes precedence.",
      );
    }
    return {
      pct: clamp(Math.round(value), 0, 100),
      doneCount: null,
      total: null,
      // Ticks follow milestones when present even in value-mode; the fill follows `value` (§9).
      ticks: milestones?.length ? ticksFrom(milestones) : null,
    };
  }

  if (milestones?.length) {
    const total = milestones.length;
    const doneCount = milestones.filter((m) => m.done).length;
    return {
      pct: total === 0 ? 0 : Math.round((doneCount / total) * 100),
      doneCount,
      total,
      ticks: ticksFrom(milestones),
    };
  }

  // Empty / uninitialised → 0%, bar still renders.
  return { pct: 0, doneCount: null, total: null, ticks: null };
}

/**
 * Resolve the *effective* label format. `"fraction"` requires milestones
 * (a non-null `total`); without them it falls back to `"percent"` + dev-warns,
 * so the readout is never `"NaN / NaN"`.
 */
export function resolveLabelFormat(
  requested: ProgressLabelFormat,
  total: number | null,
): ProgressLabelFormat {
  if (requested === "fraction" && total == null) {
    devWarn(
      "[team-progress-bar-01] labelFormat='fraction' requires `milestones`; falling back to 'percent'.",
    );
    return "percent";
  }
  return requested;
}

import type { GamificationEvent } from "../types";

/**
 * The single place the `progress-bar.checked` event shape is constructed.
 * Kept as a standalone pure factory (kit-extraction candidate, system §7.3) —
 * the component emits only this semantic event; the host adds the envelope
 * (timestamp, anonymized IDs, app variant) at its transport layer.
 */
export function progressBarCheckedEvent(teamId: string): GamificationEvent {
  return { type: "progress-bar.checked", teamId };
}

"use client";

import * as React from "react";

import type { TeamProgressBarContextValue } from "../types";

export const TeamProgressBarContext =
  React.createContext<TeamProgressBarContextValue | null>(null);

/**
 * Read the resolved progress from a surrounding `TeamProgressBarRoot`.
 * For hand-assembled layouts; throws if used outside a `Root`.
 */
export function useTeamProgressBar(): TeamProgressBarContextValue {
  const ctx = React.useContext(TeamProgressBarContext);
  if (ctx === null) {
    throw new Error(
      "useTeamProgressBar must be used within a <TeamProgressBarRoot>.",
    );
  }
  return ctx;
}

"use client";

import * as React from "react";

import { progressBarCheckedEvent } from "../lib/event";
import type { GamificationEvent } from "../types";

/**
 * "Viewed once per mount" telemetry — fires `progress-bar.checked` the first
 * time the bar scrolls ≥ 1px into the viewport, then disconnects. Pure side
 * effect (never sets state → never re-renders). SSR-safe (observer is created
 * in an effect, never during render).
 *
 * Footguns handled:
 *  - **No `onEvent` → no observer** (pay-for-what-you-use).
 *  - **Double-emit guard** via a `hasFired` ref (covers StrictMode + re-entry).
 *  - **Stable `onEvent`** read through a ref, so an inline handler (new identity
 *    each render) does not re-subscribe the observer.
 */
export function useProgressTelemetry(args: {
  teamId: string;
  onEvent?: (event: GamificationEvent) => void;
}): React.RefObject<HTMLDivElement | null> {
  const { teamId, onEvent } = args;

  const targetRef = React.useRef<HTMLDivElement | null>(null);
  const hasFired = React.useRef(false);
  const onEventRef = React.useRef(onEvent);

  React.useEffect(() => {
    onEventRef.current = onEvent;
  }, [onEvent]);

  const hasHandler = Boolean(onEvent);

  React.useEffect(() => {
    if (!hasHandler) return;
    const node = targetRef.current;
    if (!node || hasFired.current) return;

    const fire = () => {
      if (hasFired.current) return;
      hasFired.current = true;
      onEventRef.current?.(progressBarCheckedEvent(teamId));
    };

    // Old/SSR-ish environments with no IntersectionObserver: fire once on mount.
    if (typeof IntersectionObserver === "undefined") {
      fire();
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            fire();
            observer.disconnect();
            break;
          }
        }
      },
      { threshold: 0 },
    );
    observer.observe(node);
    return () => observer.disconnect();
  }, [teamId, hasHandler]);

  return targetRef;
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { useProgressTelemetry } from "../hooks/use-progress-telemetry";
import { TeamProgressBarContext } from "../hooks/use-team-progress-bar";
import { resolveLabelFormat, resolveProgress } from "../lib/resolve-progress";
import type {
  TeamProgressBarContextValue,
  TeamProgressBarRootProps,
} from "../types";

/**
 * Tier B — headless provider. The **single** place the percentage is resolved
 * and the **single** place `progress-bar.checked` fires, so every part and any
 * hand-assembly read one resolved value (the math + the emit can't drift or
 * double-fire). No data/persistence state, no layout opinion — renders children.
 */
export function TeamProgressBarRoot({
  value,
  milestones,
  team,
  labelFormat = "percent",
  onEvent,
  className,
  children,
}: TeamProgressBarRootProps) {
  const resolved = React.useMemo(
    () => resolveProgress({ value, milestones }),
    [value, milestones],
  );

  const effectiveLabelFormat = React.useMemo(
    () => resolveLabelFormat(labelFormat, resolved.total),
    [labelFormat, resolved.total],
  );

  // Telemetry target — IntersectionObserver attaches here (client-only, in an effect).
  const targetRef = useProgressTelemetry({ teamId: team.id, onEvent });

  const contextValue = React.useMemo<TeamProgressBarContextValue>(
    () => ({
      pct: resolved.pct,
      doneCount: resolved.doneCount,
      total: resolved.total,
      ticks: resolved.ticks,
      team,
      labelFormat: effectiveLabelFormat,
    }),
    [resolved, team, effectiveLabelFormat],
  );

  return (
    <TeamProgressBarContext.Provider value={contextValue}>
      <div
        ref={targetRef}
        className={cn("reveal-up flex w-full flex-col gap-1.5", className)}
      >
        {children}
      </div>
    </TeamProgressBarContext.Provider>
  );
}

"use client";

import * as React from "react";

import { Progress } from "@/components/ui/progress";
import { cn } from "@/lib/utils";

import { useTeamProgressBar } from "../hooks/use-team-progress-bar";
import type { ProgressTrackProps } from "../types";

/**
 * Tier C — dumb, context-free fill bar over the shadcn `progress` primitive.
 * Usable anywhere with a 0–100 `pct`. The signal-lime fill comes from the
 * primitive's `bg-primary` indicator; the fill transition is gated by
 * `prefers-reduced-motion` (targeting the indicator's `data-slot`). The
 * underlying Radix `Progress` already provides `role="progressbar"` +
 * `aria-valuenow/min/max` — the single accessible representation of the value.
 *
 * Ticks are rendered as a sibling overlay (NOT inside the primitive, whose Root
 * is `overflow-x-hidden` and would clip the edge notches). They are decorative
 * (`aria-hidden`) — the progressbar value is the source of truth.
 */
export function ProgressTrack({
  pct,
  ticks,
  showTicks = false,
  className,
  "aria-label": ariaLabel,
}: ProgressTrackProps) {
  const renderTicks = showTicks && ticks != null && ticks.length > 0;

  return (
    <div className={cn("relative w-full", className)}>
      <Progress
        value={pct}
        aria-label={ariaLabel}
        className={cn(
          "h-2.5 bg-muted",
          "motion-reduce:[&_[data-slot=progress-indicator]]:transition-none",
        )}
      />
      {renderTicks ? (
        <div className="pointer-events-none absolute inset-0" aria-hidden>
          {ticks.map((tick, i) => (
            <span
              key={i}
              title={tick.label}
              className={cn(
                "absolute top-0 h-full rounded-full",
                // Non-color cue: done notches are thicker + solid; pending are hairline.
                tick.done
                  ? "w-0.5 bg-primary-foreground/60"
                  : "w-px bg-muted-foreground/50",
              )}
              style={{
                insetInlineStart: `${((i + 1) / ticks.length) * 100}%`,
                transform: "translateX(-50%)",
              }}
            />
          ))}
        </div>
      ) : null}
    </div>
  );
}

/**
 * Tier B — context wrapper. Reads the resolved `pct` + `ticks` and renders the
 * Tier-C `ProgressTrack`. Builds a default `aria-label` from the team name + %.
 */
export function TeamProgressBarTrack({
  showTicks = false,
  className,
  "aria-label": ariaLabel,
}: {
  showTicks?: boolean;
  className?: string;
  "aria-label"?: string;
}) {
  const { pct, ticks, team } = useTeamProgressBar();
  const label = ariaLabel ?? `${team.name ?? "Team"} progress: ${pct}%`;

  return (
    <ProgressTrack
      pct={pct}
      ticks={ticks}
      showTicks={showTicks}
      className={className}
      aria-label={label}
    />
  );
}

"use client";

import { cn } from "@/lib/utils";

import { useTeamProgressBar } from "../hooks/use-team-progress-bar";

/**
 * Tier B — the numeric readout. Reads the resolved progress from context
 * (never re-derives it) and renders `"62%"` or `"5 / 8 milestones"`, optionally
 * prefixed with the team name (`"Team Aurora — 62%"`). The number is the
 * load-bearing value: it uses JetBrains Mono (`font-mono`), `tabular-nums`, and
 * never truncates — only the team name truncates when space is tight.
 */
export function TeamProgressBarLabel({ className }: { className?: string }) {
  const { pct, doneCount, total, team, labelFormat } = useTeamProgressBar();

  const readout =
    labelFormat === "fraction" && total != null
      ? `${doneCount} / ${total} milestones`
      : `${pct}%`;

  return (
    <div className={cn("flex items-baseline gap-1.5 text-sm", className)}>
      {team.name ? (
        <>
          <span className="min-w-0 truncate text-muted-foreground">
            {team.name}
          </span>
          <span className="text-muted-foreground" aria-hidden>
            —
          </span>
        </>
      ) : null}
      <span className="shrink-0 font-mono font-medium tabular-nums text-foreground">
        {readout}
      </span>
    </div>
  );
}
